import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { AppConstants } from 'src/app/shared/config/app.constant';
import { Subject, Observable, BehaviorSubject } from 'rxjs';



export const API_URL = AppConstants.baseURL;

@Injectable({
  providedIn: 'root'
})
export class AddSystemService {


  constructor(private http: HttpClient) { }
  private subject = new Subject<any>();
  // Post
  private Index = new BehaviorSubject<any>({
    index: '',
  })
  setIndex(index: any) {
    this.Index.next(index);
  }

  getIndex() {
    return this.Index.asObservable();
  }
  submittingAddSystem(addSsytem, user) {
    return this.http.post<any>(`${API_URL}/newExtApi/create/${user}`, addSsytem);
  }
  //geting external System
  fecthingAddSystem() {
    return this.http.get<any>(`${API_URL}/newExtApi/getAllExternalSys`);
  }
  //update
  editaddsystem(operation, currentUser, addSsytem) {
    return this.http.put<any>(`${API_URL}/newExtApi/${operation}/${currentUser}`, addSsytem)
  }
  //fetching addsystem based on id

  fetchingAddSysBasedonId(id) {
    return this.http.get<any>(`${API_URL}/newExtApi/getExternalSysDetails/${id}`)
  }
  // delete
  deleteingAddSystem() {
    return this.http.delete<any>(`${API_URL}//`);
  }
  // sendingAddSystemDataToEditScreen
  sendingAddSystemDataToEditScreen(params: any) {

    this.subject.next(params);
  }

  editruleTranslation(operation, userIdLoggedIn, messageTranslationDto) {
    return this.http.put<any>(`${API_URL}/msgApi/${operation}/${userIdLoggedIn}`, messageTranslationDto)
  }

  deleteRuleTranslation(userIdLoggedIn, transId) {
    let transIddel = new HttpParams();
    transId = transIddel.append('transId', transId);
    console.log("tra", transId);

    return this.http.delete<any>(`${API_URL}/msgApi/deleteRecord/${userIdLoggedIn}`, {
      params: transId
    });
  }

  deleteAddSystem(userIdLoggedIn, systemId) {
    return this.http.delete<any>(`${API_URL}/newExtApi/delete/${userIdLoggedIn}?systemId=${systemId}`);
  }

  getEditOfAddSystem(): Observable<any> {
    return this.subject.asObservable();
  }
  private paramSource = new BehaviorSubject({});
  getNavParam = this.paramSource.asObservable();

  sendNavParam(params: object) {
    this.paramSource.next(params)
  }
  // Audit log methods--->add System starts
  onAuthofAddSystem(addSsytem, userIdLoggedIn) {
    return this.http.put<any>(`${API_URL}/newExtApi/authorizetherecord/${userIdLoggedIn}`, addSsytem);
  }
  onCloseOfAddSystem(addSsytem, userIdLoggedIn) {
    return this.http.put<any>(`${API_URL}/newExtApi/toClosingTheRecord/${userIdLoggedIn}`, addSsytem);
  }
  onopenOfAddSystem(addSsytem, userIdLoggedIn) {
    return this.http.put<any>(`${API_URL}/newExtApi/closeRecord/${userIdLoggedIn}`, addSsytem);
  }
  onDeleteAddSystem(addSsytem, userIdLoggedIn) {
    return this.http.put<any>(`${API_URL}/newExtApi/delete/${userIdLoggedIn}`, addSsytem);
  }
  // Audit log methods--->add System ends
  // http and xml incoming
  //add system screen uplaod xml
  gettingHederofXMl(files: File) {
    var formData = new FormData();
    let key = 'header';
    formData.append('file', files);
    formData.append('key', key);

    console.log(formData);
    return this.http.post<any>(`${API_URL}/convertMsg/convertXmlToNodeTagList`, formData);
  }
  gettingBodyOfXml(files: File) {
    var formData = new FormData();
    let key = 'body';
    formData.append('file', files);
    formData.append('key', key);

    console.log(formData);
    return this.http.post<any>(`${API_URL}/convertMsg/convertXmlToNodeTagList`, formData);
  }
  // For rule transaltion upload xml
  selectFileFORHTTPXMLIncoming(files: File) {
    var formData = new FormData();

    formData.append('file', files);
    return this.http.post<any>(`${API_URL}/file/getHeaders`, formData);
  }
  fetchingXMLandHttp() {
    return this.http.get<any>(`${API_URL}/msgApi/getXmlMsgField`);
  }
  fetchingIsoForTcp() {
    return this.http.get<any>(`${API_URL}/msgApi/getIsoMsgField`);
  }
  gettinXMLmsgIncoming() {
    return this.http.get<any>(`${API_URL}/msgApi/getXmlMsgField`);
  }
  // db cnnection-->credentials api
  pingDataSource(url, driverClassName, username, password) {
    return this.http.get<[]>(`${API_URL}/db/ping/${url}/${driverClassName}/${username}/${password}`)
  }
  // db connection -->column name
  coulmnNameBasedonTableName(url, driverClassName, username, password, tablename) {
    return this.http.get<any>(`${API_URL}/db/ping/${url}/${driverClassName}/${username}/${password}/${tablename}`)
  }
  //fetching header tag
  fetchingHeaderTag() {
    return this.http.get<any>(`${API_URL}/newExtApi/getAllHeadTag`);
  }
  validateCode(code: any) {
    return this.http.get<any>(`${API_URL}/newExtApi/addSystem/validateCode/${code}`);
  }
  conversionApi(data){
    return this.http.post<any>('10.10.10.120:9191/message/readMessage',data);
  }
}
